import retrofit2.Response import retrofit2.http.Body import retrofit2.http.POST
interface ApiService {
/** POST /api/clients/register */ @POST("api/clients/register") suspend fun registerClient(@Body request: RegisterClientRequest): Response<RegisterClientResponse>
/** POST /api/auth/client/login */ @POST("api/auth/client/login") suspend fun loginClient(@Body request: LoginRequest): Response<LoginResponse> }
// ── Request DTO (espeja RegisterClientRequest del backend) ────────────────── data class RegisterClientRequest( val email: String, val password: String, val name: String, val termsAccepted: Boolean, val language: String, // "en" | "es" val picDirectory: String? = null )
// ── Response DTO (espeja RegisterClientResponse del backend) ───────────────── data class RegisterClientResponse( val id: Long, val email: String, val name: String, val status: String, val language: String, val createdAt: String, val termsAccepted: Boolean, val picDirectory: String?, val role: String )
