import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import java.util.Locale

/**
 * ViewModel for the partner registration screen.
 * Holds UI state and calls the backend endpoint.
 */
class RegisterViewModel : ViewModel() {

    sealed interface RegisterUiState {
        object Idle : RegisterUiState
        object Loading : RegisterUiState
        object Success : RegisterUiState
        data class Error(val message: String) : RegisterUiState
    }

    private val _uiState = MutableStateFlow<RegisterUiState>(RegisterUiState.Idle)
    val uiState: StateFlow<RegisterUiState> = _uiState.asStateFlow()

    fun register(
        name: String,
        email: String,
        password: String,
        areaId: Int,
        termsAccepted: Boolean
    ) {
        viewModelScope.launch {
            _uiState.value = RegisterUiState.Loading
            try {
                val language = if (Locale.getDefault().language == "es") "es" else "en"
                val request = RegisterPartnerRequest(
                    email = email.trim(),
                    password = password,
                    name = name.trim(),
                    areaId = areaId,
                    termsAccepted = termsAccepted,
                    language = language
                )
                val response = RetrofitClient.apiService.registerPartner(request)
                if (response.isSuccessful) {
                    _uiState.value = RegisterUiState.Success
                } else {
                    val errorBody = response.errorBody()?.string()
                    _uiState.value = RegisterUiState.Error(
                        parseErrorMessage(response.code(), errorBody)
                    )
                }
            } catch (e: Exception) {
                _uiState.value = RegisterUiState.Error(
                    parseErrorMessage(e)
                )
            }
        }
    }

    fun resetState() {
        _uiState.value = RegisterUiState.Idle
    }

    private fun parseErrorMessage(code: Int, body: String?): String = when (code) {
        409  -> "Email already registered."
        400  -> "Invalid data. Check all fields."
        else -> "Server error ($code). Please try again."
    }

    private fun parseErrorMessage(exception: Exception): String {
        return when {
            exception.message?.contains("failed to connect") == true -> {
                "Connection failed. Make sure the backend is running on http://10.0.2.2:8080"
            }
            exception.message?.contains("timeout") == true -> {
                "Connection timeout. Check your network and backend status."
            }
            exception.message?.contains("Connection refused") == true -> {
                "Backend refused connection. Is it running?"
            }
            else -> {
                "Error: ${exception.localizedMessage ?: "Unknown error"}"
            }
        }
    }
}

package com.sismptm.partner.utils

/**
 * Configuración de ambiente para desarrollo y producción.
 * Actualiza este archivo según el ambiente en el que estés trabajando.
 */
object EnvironmentConfig {

    /**
     * Set to true cuando estés usando un dispositivo físico
     * Set to false cuando estés usando un emulador Android
     */
    const val IS_PHYSICAL_DEVICE = false

    /**
     * Para Emulador: 10.0.2.2 apunta a localhost en tu máquina host
     * Para Dispositivo Físico: Usar la IP de tu máquina en la red local
     * Ejemplo: "192.168.1.100"
     */
    const val BACKEND_HOST = if (IS_PHYSICAL_DEVICE) {
        // Reemplaza esto con la IP de tu máquina
        "192.168.1.100"
    } else {
        // Para emulador
        "10.0.2.2"
    }

    const val BACKEND_PORT = 8080

    const val BACKEND_PROTOCOL = "http" // "http" para desarrollo, "https" para producción

    val BACKEND_URL: String
        get() = "$BACKEND_PROTOCOL://$BACKEND_HOST:$BACKEND_PORT/"

    // BuildType (puedes usar BuildConfig.BUILD_TYPE si está disponible)
    val IS_DEBUG: Boolean = true

    // Logging
    val ENABLE_NETWORK_LOGGING: Boolean = IS_DEBUG
}

